function gradeClass(g) {
  if (!g) return 'grade';
  var u = g.toUpperCase();
  if (u === 'A') return 'grade grade-a';
  if (u === 'B') return 'grade grade-b';
  if (u === 'C') return 'grade grade-c';
  return 'grade';
}
function render(model) {
  var allParts = model.installedParts || [];
  var parts = allParts.filter(function (p) {
    return p.installed_in_asset_id !== null;
  });
  var tbody = document.getElementById('table_body');
  var count = document.getElementById('count');
  if (!tbody || !count) return;
  count.textContent = parts.length + ' part' + (parts.length !== 1 ? 's' : '');
  if (!parts.length) {
    tbody.innerHTML = '<tr><td colspan="5" class="empty">No parts installed</td></tr>';
    return;
  }
  var total = 0;
  var hasAny = false;
  var rows = parts.map(function (p) {
    var cost = p.part_cost ? parseFloat(p.part_cost) : null;
    if (cost !== null) {
      total += cost;
      hasAny = true;
    }
    var spec = p.spec && p.spec !== 'null' && p.spec !== '' ? p.spec : '—';
    var grade = p.condition_grade && p.condition_grade !== 'null' ? p.condition_grade.toUpperCase() : 'N';
    var costStr = cost !== null ? '£' + cost.toFixed(2) : '—';
    return '<tr>' + '<td><span class="part-ref">' + (p.part_ref || '—') + '</span></td>' + '<td>' + (p.part_type || '—') + '</td>' + '<td style="color:#6b7280">' + spec + '</td>' + '<td><span class="' + gradeClass(grade) + '">' + grade + '</span></td>' + '<td>' + costStr + '</td>' + '</tr>';
  }).join('');
  if (hasAny) {
    rows += '<tr><td colspan="4" style="text-align:right;font-size:11px;color:#6b7280;padding-top:10px">Total parts cost</td>' + '<td style="font-weight:500;padding-top:10px">£' + total.toFixed(2) + '</td></tr>';
  }
  tbody.innerHTML = rows;
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  render(model);
});

